"""
MKT Original Commentary — Genesis chapters 10–12
Run: python3 scripts/zc-original-genesis-10-12.py

Source data used:
- data/interlinear/genesis.json
- data/translation/glossary-hebrew.json
- data/translation/draft/mediating/genesis.json (MKT text)

Key decisions:
- Ch 10: Table of Nations uses a threefold organizing formula (clans, languages,
  territories, nations) — the formula appears verbatim for Japheth, Ham, and Shem;
  the Hebrew root connections (Eber → Hebrew; Peleg → division; Nimrod → defiant
  hunter) are given without dogmatic identification of ancient peoples
- Ch 11 Babel: the cohortative "let us" mirrors the divine cohortative of 1:26;
  Babel's name plays on Hebrew balal (confuse) vs. Akkadian Bab-ilim (gate of
  the gods) — the narrator deconstructs the city's own self-glorifying name;
  the genealogical lifespan decline from Shem to Terah is noted as a structural
  transition to the patriarchal era
- Ch 12 lek-leka: the doubled imperative with reflexive force; Abram's call reverses
  Babel's attempt to stay put and make a name — God scatters (Babel), calls one out
  (Abram), and makes the name great that the tower-builders tried to make themselves;
  nibrekhu (12:3) debated Niphal/Hitpael — both readings have ancient support; the
  MT form is Niphal passive, favoring Paul's reading in Gal 3:8
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS = {
  "10": {
    "1": '<p><strong>אֵלֶּה תּוֹלְדֹת</strong> (<em>ʾēlleh tôlĕḏōt</em>) — "these are the generations/account of." The <em>tôlĕḏōt</em> formula (cf. 2:4; 5:1; 6:9; 11:10; 11:27; 25:12, 19; 36:1; 37:2) opens a new section of Genesis. Here it introduces the Table of Nations — not a genealogy in the strict biological sense but a political-ethnic mapping of the known world from Noah\'s three sons. The organizing principle is threefold: clans (<em>mišpĕḥōtām</em>), languages (<em>bilšōnōtām</em>), and lands/nations (<em>bĕʾarṣōtām lĕgôyêhem</em>) — the same formula closes each of the three son-sections (vv. 5, 20, 31) and the chapter itself (v. 32).</p>',
    "2": '<p>Japheth\'s seven sons are broadly associated with the northern and western peoples of the ancient Near East: <strong>גֹּמֶר</strong> (<em>Gomer</em>) = Cimmerians (Gimirrai in Assyrian); <strong>מָגוֹג</strong> (<em>Māgōg</em>) = a northern people, associated with eschatological enemies in Ezek 38-39; <strong>מָדַי</strong> (<em>Māḏay</em>) = Medes; <strong>יָוָן</strong> (<em>Yāwān</em>) = Ionia/Greeks (<em>Yavan</em> in Sanskrit and cognate languages); <strong>תֻּבָל</strong> (<em>Tûbāl</em>) = Tabal (Anatolia); <strong>מֶשֶׁךְ</strong> (<em>Mešeḵ</em>) = Mushki (Cappadocia); <strong>תִּירָס</strong> (<em>Tîrās</em>) = Tyrrhenians/Thracians (identification uncertain). The list is not intended to be exhaustive but representative of the Japhethite sphere.</p>',
    "3": '<p>Gomer\'s sons: <strong>אַשְׁכְּנַז</strong> (<em>ʾAšḵĕnaz</em>) = Scythians (Aškuzai in Assyrian sources); <strong>רִיפַת</strong> (<em>Rîpaṯ</em>) = possibly Paphlagonians or Celts; <strong>תֹּגַרְמָה</strong> (<em>Tôḡarmāh</em>) = Til-garimmu, a region in southeastern Anatolia, associated with horse-trading (Ezek 27:14; 38:6). These second-generation descendants of Japheth begin to fill in the northwestern tier of the ancient world known to the author.</p>',
    "4": '<p>Javan\'s sons represent the Greek world and its periphery: <strong>אֱלִישָׁה</strong> (<em>ʾĔlîšāh</em>) = Alashiya (Cyprus) or possibly Elis; <strong>תַּרְשִׁישׁ</strong> (<em>Taršîš</em>) = Tartessos in Spain or possibly Sardinia — a far-western trading destination (cf. Jonah 1:3; 1 Kgs 10:22); <strong>כִּתִּים</strong> (<em>Kittîm</em>) = Kition in Cyprus, later used broadly for western maritime powers including Rome (Dan 11:30; Num 24:24); <strong>דֹּדָנִים</strong> (<em>Dōḏānîm</em>) = possibly Dodaneans/Rhodians, or (with textual variant) Rodanites.</p>',
    "5": '<p><strong>מֵאֵלֶּה נִפְרְדוּ אִיֵּי הַגּוֹיִם</strong> — "from these the coastland peoples of the nations were separated/spread out." <em>Nāpraḏ</em> (Niphal of <em>pāraḏ</em>, to be separated, divided) — the same verb root as Peleg\'s name (10:25) and implicit in the Babel scattering. The coastland peoples (<em>ʾiyyê haggôyim</em> = islands/coastlands of the nations) identifies the Japhethites as the maritime-western peoples. The threefold formula closes this section: <em>lĕmišpĕḥōtām bĕlišōnōtām bĕʾarṣōtām bĕgôyêhem</em> — by their clans, by their languages, in their lands, within their nations.</p>',
    "6": '<p>Ham\'s sons map onto Africa and the ancient Near East: <strong>כּוּשׁ</strong> (<em>Kûš</em>) = Ethiopia/Nubia; <strong>מִצְרַיִם</strong> (<em>Miṣrāyim</em>) = Egypt (the dual form suggests Upper and Lower Egypt); <strong>פּוּט</strong> (<em>Pûṭ</em>) = Libya or Somalia (identification debated; Nah 3:9 places Put near Egypt); <strong>כְּנָעַן</strong> (<em>Kĕnaʿan</em>) = Canaan. The listing of Canaan last, after three African/Nilotic peoples, places Canaan in a subordinate position — and given the curse of 9:25, this positioning is significant. Ham\'s line will include both the great imperial powers (Egypt, Babylon through Nimrod) and the promised-land occupants.</p>',
    "7": '<p>Cush\'s sons extend southward and eastward: <strong>שְׁבָא</strong> (<em>Šĕbāʾ</em>) = Saba/Sheba (Arabia or East Africa — the Queen of Sheba, 1 Kgs 10:1); <strong>דְּדָן</strong> (<em>Dĕḏān</em>) = an Arabian trading center (Jer 25:23; Ezek 27:15-20). These Cushite-descended peoples in Arabia represent the commercial network of the ancient incense trade routes.</p>',
    "8": '<p><strong>וְנִמְרֹד הֵחֵל לִהְיוֹת גִּבֹּר בָּאָרֶץ</strong> — "Nimrod began to be a mighty warrior/hero in the earth." <em>Gîbbōr</em> (mighty warrior, hero — from <em>gābar</em>, to be strong, prevail) is used of warriors (2 Sam 23:8-39), Saul and Jonathan (2 Sam 1:19, 25, 27), and God himself as the divine warrior (Ps 24:8; Isa 42:13; Zeph 3:17). The Hiphil <em>hēḥēl</em> (began) echoes 4:26 (people began to call on the LORD\'s name) and 6:1 (people began to multiply) — the verb marks significant new beginnings, not always positive. Nimrod is the first named human "mighty one" — a political-military category that sets him apart from the genealogical norm.</p>',
    "9": '<p><strong>גִּבֹּר-צַיִד לִפְנֵי יְהוָה</strong> (<em>gibbōr-ṣayiḏ lipnê YHWH</em>) — "a mighty hunter <em>before</em> the LORD." The expression <em>lipnê YHWH</em> (before the LORD, in YHWH\'s sight) can mean: (1) in God\'s presence/sight (a positive superlative — supremely great); (2) before/in front of God (as a rival or opponent — the Targum Onqelos adds "in defiance of"). The proverb attached ("like Nimrod a mighty hunter before the LORD") preserves an ancient saying. Given Nimrod\'s connection to Babel (v. 10), the "defiance" reading has textual support — the great-city builder and the one who hunted before God fit the Babel narrative\'s spirit of rival-to-divine ambition.</p>',
    "10": '<p><strong>רֵאשִׁית מַמְלַכְתּוֹ בָּבֶל</strong> (<em>rēʾšît mamlaktô bābel</em>) — "the beginning of his kingdom was Babylon." <em>Bābel</em> appears here first in Genesis — immediately before the Babel narrative of ch. 11. Nimrod\'s kingdom (the first named human kingdom in the OT) begins at Babel and extends to Nineveh — the two great enemy cities of the OT prophets. <strong>שִׁנְעָר</strong> (<em>Šinʿār</em>) = Sumer/Babylonia — the same region as the Babel event (11:2). Nimrod\'s Babel is the historical/political root of the Babel tower-city project.</p>',
    "11": '<p><strong>מִן-הָאָרֶץ הַהִוא יָצָא אַשּׁוּר</strong> — either "from that land he [Nimrod] went to Assyria" or "from that land Asshur went out" (subject ambiguous). If Nimrod, he extends his empire northward to Assyria — consistent with a Hamite building the great Assyrian cities. If Asshur, the text may simply trace the geographical spread of Assyria. The cities named — <strong>נִינְוֵה</strong> (<em>Nînĕwēh</em>, Nineveh), the great Assyrian capital — are historically attested from at least the 3rd millennium BCE.</p>',
    "12": '<p><strong>הִוא הָעִיר הַגְּדֹלָה</strong> — "that is the great city." The designation "great city" (<em>hāʿîr haggĕḏōlāh</em>) is used in Jonah 1:2; 3:2-3; 4:11 for Nineveh — the city of 120,000 people that Jonah was sent to preach in. This parenthetical label connects the Table of Nations genealogy to the Jonah narrative — Nineveh\'s greatness originates in Nimrod\'s founding, and its significance will appear in the prophetic literature of 2 Kings and Jonah.</p>',
    "13": '<p><strong>מִצְרַיִם</strong> (<em>Miṣrāyim</em>, Egypt) as father of peoples — the sons of Egypt are the peoples inhabiting the Nile Delta and surrounding regions. <strong>לוּדִים</strong> (<em>Lûḏîm</em>) = Lydians or Libyans; <strong>פְּלִשְׁתִּים</strong> (<em>Pĕlištîm</em>, Philistines) are traced in v. 14 to the Kasluhites through Egypt — placing Israel\'s great adversaries within the Hamitic genealogical framework. The Philistines originating from Egyptian stock is consistent with Egyptian administrative presence in Canaan during the Late Bronze Age.</p>',
    "14": '<p><strong>כַּסְלֻחִים אֲשֶׁר יָצְאוּ מִשָּׁם פְּלִשְׁתִּים</strong> — "the Kasluhites, from whom the Philistines came." The parenthetical identification of the Philistines\' Egyptian origin is textually noted but geographically the Philistines are most closely associated with the Aegean Sea Peoples (the Peleset of Egyptian records, 12th century BCE) who settled in Canaan\'s coastal plain. <strong>כַּפְתֹּרִים</strong> (<em>Kaptōrîm</em>) = Cretans — Amos 9:7 explicitly identifies the Philistines\' origin as Caphtor (Crete), making the Kasluhite parenthetical and the Caphtorite line different traditional strands.</p>',
    "15": '<p><strong>כְּנַעַן יָלַד אֶת-צִידֹן בְּכֹרוֹ</strong> — "Canaan fathered Sidon his firstborn." <em>Ṣîḏōn</em> (Sidon) is named the firstborn son of Canaan — the great Phoenician coastal city, Israel\'s northern neighbor and the source of the cedars of Lebanon. The list that follows (Hittites, Jebusites, Amorites, Girgashites, Hivites, etc.) is the standard Canaanite nations list of the Pentateuch (cf. Exod 3:8, 17; 23:23; 33:2; Deut 7:1; 20:17) — the Table of Nations is also a land-grant document, mapping the territory that Israel will later claim as Abrahamic promise fulfilled.</p>',
    "16": '<p><strong>יְבוּסִי</strong> (<em>Yĕbûsî</em>, Jebusites) — the pre-Israelite inhabitants of Jerusalem (2 Sam 5:6-9; Josh 15:63). <strong>אֱמֹרִי</strong> (<em>ʾĔmōrî</em>, Amorites) — a broad term for highland Canaanites (cf. Num 13:29; Josh 10:5-6; Amos 2:9-10). These peoples are genealogically located as Canaanites descended from Ham — the Abrahamic covenant will involve displacing Ham\'s cursed line (9:25-27) in fulfillment of the blessing on Shem.</p>',
    "17": '<p><strong>חִוִּי</strong> (<em>Ḥiwwî</em>, Hivites) — inhabitants of Gibeon (Josh 9:7; 11:19) and Shechem (Gen 34:2). <strong>עַרְקִי</strong> (<em>ʿArqî</em>, Arkites) — from Tell Arqa in northern Lebanon. <strong>סִינִי</strong> (<em>Sînî</em>, Sinites) — possibly from the region around Tell Kazel in northern Lebanon (the Siyannu of Ugaritic texts). These third-tier names in the Canaanite list represent specific city-states and clans rather than major ethnic groups.</p>',
    "18": '<p><strong>וְאַחַר נָפֹצוּ מִשְׁפְּחוֹת הַכְּנַעֲנִי</strong> — "afterward the clans of the Canaanites spread abroad." <em>Nāpōṣ</em> (Niphal of <em>pûṣ</em>, to scatter, be dispersed) — the same verb as the Babel scattering (11:4: <em>pen-nāpûṣ</em>) and its fulfillment (11:8-9). The Canaanite dispersion anticipates the Babel narrative\'s scattering and the later displacement of Canaan by Israel as fulfillment of 9:25-27.</p>',
    "19": '<p>The geographical boundaries of Canaan are given: from Sidon southward to Gaza (Mediterranean coast), then inland toward Sodom, Gomorrah, Admah, Zeboiim to Lasha. The southern boundary cities (Sodom, Gomorrah, Admah, Zeboiim) are exactly the cities of the plain that will be destroyed in ch. 19 — the Table of Nations implicitly marks the doomed cities within the Canaanite territorial definition. Canaan\'s eastern boundary reaches toward the Dead Sea region.</p>',
    "20": '<p>The closing formula for Ham\'s descendants: <em>ʾēlleh bĕnê-ḥām lĕmišpĕḥōtām bilšōnōtām bĕʾarṣōtām bĕgôyêhem</em> — "these are the sons of Ham by their clans, by their languages, in their lands, in their nations." The fourfold formula (clans / languages / lands / nations) is identical for all three sons (vv. 5, 20, 31) — the same structural grid organizes all three genealogical lists, suggesting intentional literary organization of the total human family.</p>',
    "21": '<p><strong>וּלְשֵׁם יֻלַּד גַּם-הוּא</strong> — "and to Shem also children were born." The narrative interest tips toward Shem at this point — he is identified as <em>ʾăbî kol-bĕnê-ʿēber</em> (ancestor of all the sons of Eber). <strong>עֵבֶר</strong> (<em>ʿĒber</em>) — the eponymous ancestor of the Hebrews (<em>ʿibrî</em>). The same consonants spell "crossing over" (<em>ʿābēr</em>) — possibly signifying those who crossed the Euphrates, those from "the other side" (Josh 24:2-3). Shem\'s genealogical line will narrow through Eber to Peleg to Terah to Abram — the Table of Nations is also a road map to the covenant line.</p>',
    "22": '<p>Shem\'s five sons: <strong>עֵילָם</strong> (<em>ʿÊlām</em>) = Elam (southwestern Iran); <strong>אַשּׁוּר</strong> (<em>ʾAššûr</em>) = Assyria; <strong>אַרְפַּכְשַׁד</strong> (<em>ʾArpaḵšaḏ</em>) = uncertain identification (possibly the Chaldean homeland or Arrapkha in northern Iraq) — the ancestor of Eber and thus of Abram; <strong>לוּד</strong> (<em>Lûḏ</em>) = Lydia (western Anatolia); <strong>אֲרָם</strong> (<em>ʾĂrām</em>) = Aram/Syria. Through Arphaxad runs the Abrahamic covenant line.</p>',
    "23": '<p>Aram\'s sons represent the Aramaic-speaking peoples: <strong>עוּץ</strong> (<em>ʿÛṣ</em>) = the land of Uz, home of Job (Job 1:1; Lam 4:21); <strong>חוּל</strong> (<em>Ḥûl</em>), <strong>גֶּתֶר</strong> (<em>Geter</em>), <strong>מַשׁ</strong> (<em>Maš</em> or Meshech, variant reading) — these represent the Aramaean city-states that will be significant in Israel\'s political history (Syria, 2 Sam 8:6; 1 Kgs 20:34; 2 Kgs 16:5-9).</p>',
    "24": '<p><strong>וְאַרְפַּכְשַׁד יָלַד אֶת-שָׁלַח וְשֶׁלַח יָלַד אֶת-עֵבֶר</strong> — "Arphaxad fathered Shelah, and Shelah fathered Eber." The genealogical line is narrowing: from Shem\'s five sons, through Arphaxad alone, to Eber. This line will continue in the post-Babel genealogy of ch. 11 with even greater specificity, leading to Terah and Abram. The Table of Nations is simultaneously a full-world ethnography and a progressive narrowing toward the covenant recipient.</p>',
    "25": '<p><strong>וּלְעֵבֶר יֻלַּד שְׁנֵי בָנִים שֵׁם הָאֶחָד פֶּלֶג כִּי בְיָמָיו נִפְלְגָה הָאָרֶץ</strong> — "Two sons were born to Eber: the name of the one was Peleg, for in his days the earth was divided." <em>Peleḡ</em> from <em>pālaḡ</em> (to divide, split) — the wordplay is explicit. "In his days the earth was divided" — most naturally referring to the Babel event of ch. 11, where God divides/scatters humanity. Peleg\'s name thus timestamps the Babel dispersion: it happened within his generation. Alternatively, some read "divided" as a reference to continental geography (less likely given the context). The genealogical note connects the Table of Nations to the Babel narrative chronologically.</p>',
    "26": '<p>Joktan\'s thirteen sons (vv. 26-29) represent the various tribes and regions of southern Arabia — Almodad, Sheleph, Hazarmaveth (= Hadramawt in Yemen), Jerah (lunar-deity name), and others. These are among the most obscure names in the Table of Nations; several can be tentatively connected to known South Arabian place names and peoples through archaeology and comparative Semitic studies.</p>',
    "27": '<p>Hadoram, Uzal, Diklah — these Joktanite names continue the South Arabian tribal geography. <strong>עוּזָל</strong> (<em>ʿûzāl</em>) may correspond to the ancient city Uzal (= Sanaa in Yemen, according to Arabic tradition). The density of names in the Joktanite list without additional narrative material signals that these peoples were known to the author\'s audience but peripheral to the biblical narrative\'s primary interests.</p>',
    "28": '<p>Obal, Abimael, Sheba — <strong>שְׁבָא</strong> (<em>Šĕbāʾ</em>) appears both as a Cushite son (v. 7, through Ham) and here as a Joktanite son (through Shem). The double occurrence may reflect the two known Sheba/Saba regions — one East African, one South Arabian — or the fact that the same tribal name existed in two different genealogical traditions. The Queen of Sheba (1 Kgs 10:1-13) is associated with the South Arabian Saba.</p>',
    "29": '<p><strong>אוֹפִר</strong> (<em>ʾÔpîr</em>, Ophir) — the famous source of gold sought by Solomon\'s navy (1 Kgs 9:28; 10:11; 22:48; Job 22:24; 28:16; Ps 45:9; Isa 13:12). Ophir\'s precise location is debated (India, Arabia, or East Africa), but its genealogical placement among the Joktanite South Arabians tips toward an Arabian or East African identification. <strong>יוֹבָב</strong> (<em>Yôbāb</em>) — possibly connected etymologically to the name Job (<em>ʾiyyôb</em>), though the identification is uncertain.</p>',
    "30": '<p>The geographical extent of Joktan\'s descendants — from Mesha to Sephar in the eastern hill country — is another pair of location-markers that resist confident modern identification. <em>Meša</em> and <em>Sĕpar</em> likely represent the western and eastern limits of the South Arabian region where the Joktanite tribes settled.</p>',
    "31": '<p>The Shem-section closing formula mirrors v. 5 and v. 20: <em>lĕmišpĕḥōtām bilšōnōtām bĕʾarṣōtām lĕgôyêhem</em> — "by their clans, by their languages, in their lands, by their nations." The Semitic peoples, including the ancestors of both the Arabians (through Joktan) and the Hebrews (through Peleg to Eber to Arphaxad to Shem), are mapped out before the Babel narrative that explains why they are now distributed.</p>',
    "32": '<p><strong>מֵאֵלֶּה נִפְרְדוּ הַגּוֹיִם בָּאָרֶץ אַחַר הַמַּבּוּל</strong> — "from these the nations were separated/scattered in the earth after the flood." The verb <em>nāpraḏ</em> (Niphal of <em>pāraḏ</em>, to separate, be scattered) provides the theological bracket: the diversity of nations was not an accident but a separation. The Table of Nations implicitly anticipates the Babel narrative\'s explanation of how this separation happened. The phrase "after the flood" grounds the entire human diversification in the post-Noah world — the whole table is a post-diluvian re-population.</p>'
  },
  "11": {
    "1": '<p><strong>שָׂפָה אַחַת וּדְבָרִים אֲחָדִים</strong> (<em>śāpāh ʾaḥat ûḏĕbārîm ʾăḥāḏîm</em>) — "one language and common/unified speech." Two terms for language: <em>śāpāh</em> (lip, language — lit. the speech-producing organ, used as a metonymy for language) and <em>ḏĕbārîm ʾăḥāḏîm</em> (common/unified words — the same speech content, not just the same language). The pre-Babel condition was linguistic unity — a single system of meaning shared by all humanity. This will be the condition restored eschatologically (Zeph 3:9: "I will give peoples pure speech/lips").</p>',
    "2": '<p><strong>בְּנָסְעָם מִקֶּדֶם</strong> (<em>bĕnāsĕʿām miqqeḏem</em>) — "as they journeyed eastward/from the east." The direction is ambiguous: either they moved east (Cain also went east, 4:16; Lot goes east toward Sodom, 13:11 — east = away from God in Genesis) or they came from the east. <strong>בִּקְעַת שִׁנְעָר</strong> (<em>biqʿat šinʿār</em>) — "the plain of Shinar," the same location as Nimrod\'s kingdom (10:10). The deliberate settling (<em>wayyēšĕbû šām</em>) reverses the command to fill the earth (1:28; 9:1) — they settle, concentrate, and build rather than scatter and fill.</p>',
    "3": '<p><strong>הָבָה נִלְבְּנָה לְבֵנִים</strong> (<em>hābāh nilbĕnāh lĕbēnîm</em>) — "come, let us make bricks." The cohortative plural (three cohortatives in vv. 3-4: <em>nilbĕnāh</em>, <em>nibĕneh</em>, <em>naʿăśeh</em>) echoes and parodies the divine cohortative of 1:26 ("let us make mankind") — humans now say "let us make" in deliberate mimicry of the divine creative "let us." The building materials are noted: <em>lĕbēnāh</em> (brick, kiln-fired) instead of <em>ʾeḇen</em> (stone), and <em>ḥēmār</em> (bitumen/asphalt) instead of <em>śîḏ</em> (lime/mortar). The parenthetical observation contrasts Mesopotamian construction (brick and bitumen — the standard materials in the alluvial plain of Shinar, where stone is unavailable) with Palestinian/Canaanite construction (stone and lime). The narrator implicitly critiques the substitute materials: synthetic brick instead of natural stone, petroleum tar instead of lime.</p>',
    "4": '<p><strong>הָבָה נִבְנֶה-לָּנוּ עִיר וּמִגְדָּל</strong> — "come, let us build for ourselves a city and a tower." <em>Lānû</em> (for ourselves) — the self-referential purpose is emphasized: the construction is for their own benefit, consolidation, and glory. <em>Migdāl</em> (tower) — from <em>gāḏal</em> (to be great) — a great tower. <strong>וְרֹאשׁוֹ בַשָּׁמַיִם</strong> — "with its top in the heavens" — the expression is idiomatic for extraordinary height (cf. Deut 1:28: "cities great and fortified up to heaven"; Dan 4:11: the tree reaching to heaven). It need not be taken literally as an attempt to climb to the divine realm.</p><p><strong>וְנַעֲשֶׂה-לָּנוּ שֵׁם</strong> (<em>wĕnaʿăśeh-lānû šēm</em>) — "and let us make a name for ourselves." <em>Šēm</em> (name, reputation, fame) — this is the exact reversal of what God will do for Abram (12:2: "I will make your name great"). The builders seek to establish their own <em>šēm</em> through construction; God\'s plan is to establish the <em>šēm</em> of his chosen one through covenant. <strong>פֶּן-נָפוּץ</strong> (<em>pen-nāpûṣ</em>) — "lest we be scattered" — the very scattering they feared (and tried to prevent by city-building) is precisely what God brings about (v. 8). They resist the mandate to fill the earth (1:28; 9:1) by deliberately concentrating.</p>',
    "5": '<p><strong>וַיֵּרֶד יְהוָה לִרְאוֹת אֶת-הָעִיר וְאֶת-הַמִּגְדָּל</strong> — "and the LORD came down to see the city and the tower." The anthropomorphic irony is sharp: the tower built to reach the heavens requires God to "come down" to see it. The verb <em>yāraḏ</em> (to come down, descend) undercuts the tower\'s pretension — what the builders thought was heaven-reaching, the deity can only see by descending from his actual dwelling. The narrative\'s irony is literary theology: the human project is small enough that God must stoop to see it.</p>',
    "6": '<p><strong>הֵן עַם אֶחָד וְשָׂפָה אַחַת לְכֻלָּם</strong> — "behold, one people and one language for all of them." God\'s assessment begins with what he sees: unity of language and people. <strong>וְזֶה הַחִלָּם לַעֲשׂוֹת</strong> — "and this is only the beginning of what they will do" — <em>ḥillam</em> (their beginning) = infinitive of <em>ḥālal</em>, to begin. <strong>לֹא-יִבָּצֵר מֵהֶם כֹּל אֲשֶׁר יָזְמוּ לַעֲשׂוֹת</strong> — "nothing will be withheld from them that they purpose to do" — <em>bāṣar</em> (Niphal, to be withheld, cut off, inaccessible) — their unified capability poses a theological challenge: not that humans can actually reach God\'s heaven, but that human technological and political unity can amplify sin enormously. The divine response is not punishment for the tower itself but dispersal to limit the scope of unified human rebellion.</p>',
    "7": '<p><strong>הָבָה נֵרְדָה וְנָבְלָה שָׁם שְׂפָתָם</strong> — "come, let us go down and confuse their language there." The divine cohortative <em>hābāh nērĕḏāh</em> (come, let us go down) directly mirrors and reverses the human cohortatives of vv. 3-4 (<em>hābāh nilbĕnāh</em>, <em>hābāh nibĕneh-lānû</em>): as the humans said "let us make" and "let us build," God says "let us go down." The divine response is structured as a counter-action to the human initiative, step by step. The "us" (<em>nērĕḏāh</em>, first-person plural cohortative) is the same plural as 1:26 — the divine council or the Trinitarian "us" — unexplained but deliberate.</p>',
    "8": '<p><strong>וַיָּפֶץ יְהוָה אֹתָם מִשָּׁם עַל-פְּנֵי כָל-הָאָרֶץ</strong> — "so the LORD scattered them from there over the face of all the earth." The verb <em>pûṣ</em> (Hiphil: to cause to be scattered, disperse) fulfills exactly what they feared (<em>pen-nāpûṣ</em>, v. 4). What they built the city to prevent, God brings about. The scattering is also the fulfillment of the original mandate: <em>milĕʾû ʾet-hāʾāreṣ</em> (fill the earth, 1:28; 9:1) — God scatters them so the earth is filled as originally commanded, if not as they originally intended.</p>',
    "9": '<p><strong>עַל-כֵּן קָרָא שְׁמָהּ בָּבֶל</strong> — "therefore its name is called Babel." The narrative etymology: <em>bābel</em> from Hebrew <em>bālal</em> (to confuse, mix — the verb used in v. 7: <em>nābĕlāh śĕpātām</em>, we will confuse their language). But the Akkadian name <em>Bab-ilim</em> means "gate of the god(s)" — the Babylonians understood their great city as the gateway between earth and heaven. The Hebrew narrator deconstructs this self-glorifying name: what the Babylonians called the "gate of God," the Bible calls "confusion." The wordplay subverts Babylon\'s entire self-understanding — its foundational claim to cosmic status is a pun on "confusion."</p>',
    "10": '<p><strong>אֵלֶּה תּוֹלְדֹת שֵׁם</strong> — "these are the generations/account of Shem." The <em>tôlĕḏōt</em> formula opens the post-Babel genealogy. This second Shem genealogy (compare 10:21-31) narrows from the broad Table of Nations to a single focused line: Shem → Arphaxad → Shelah → Eber → Peleg → Reu → Serug → Nahor → Terah → Abram. The precision of the genealogy (age at fathering, years remaining, total lifespan) matches the pre-flood genealogy of ch. 5, but lifespans decline sharply.</p>',
    "11": '<p>Shem\'s total lifespan: 100 years before Arphaxad + 500 years after = 600 years. Shem is the longest-lived of the post-flood patriarchs and, remarkably, outlives Abraham (who dies at 175, 25:7) — Shem was still alive during Abraham\'s lifetime by the genealogical arithmetic. The genealogy from Noah to Abraham spans approximately 10 generations, mirroring the antediluvian 10 generations from Adam to Noah (ch. 5).</p>',
    "12": '<p>Arphaxad\'s 35 years to fathering Shelah marks the beginning of the post-Babel genealogical line. The form of each entry (<em>wayyiḥî X ben-N šānāh wayyôleḏ ʾet-Y</em>, "X lived N years and fathered Y") uses the same waw-consecutive structure as ch. 5, creating a formal parallel between the antediluvian and post-Babel genealogies — two symmetrical spans between catastrophes (Flood; Babel) leading to the Patriarchal era.</p>',
    "13": '<p>Arphaxad\'s remaining 403 years after Shelah: total lifespan 438 years. The lifespan is already dramatically shorter than Shem\'s 600 — the post-Babel genealogy shows a systematic, generation-by-generation decline in longevity: Shem (600) → Arphaxad (438) → Shelah (433) → Eber (464) → Peleg (239) → Reu (239) → Serug (230) → Nahor (148) → Terah (205). The pattern is not perfectly linear but the trend is unmistakable: the antediluvian world (Adam to Noah: 930, 912, 905, 910, 895, 962, 365, 969, 777, 950 years) is giving way to the patriarchal world.</p>',
    "14": '<p>Shelah after 30 years fathers Eber — the eponymous ancestor of the Hebrews. The brevity of the genealogical entries in vv. 12-25 reflects their structural-transitional function rather than narrative interest. Each entry confirms the unbroken chain from Shem to Abram, establishing the genealogical continuity of the covenant line across the post-Babel dispersion.</p>',
    "15": '<p>Shelah\'s additional 403 years: total 433. The regularity of the numerical pattern (30-35 years before fathering, then 200-430 years remaining) may reflect a schematic presentation rather than precise chronological record — as in ch. 5, the genealogy\'s theological function (continuity of the promise line) is primary; the numbers establish the bridge between the flood and the patriarchs.</p>',
    "16": '<p>Eber after 34 years fathers Peleg. <strong>עֵבֶר</strong> (<em>ʿĒber</em>) — the eponymous ancestor whose name gives "Hebrew" (<em>ʿibrî</em>). Eber is unusual in having the longest lifespan of the post-Babel patriarchs (464 years, v. 17), longer even than Shem (600 is longer, but Eber\'s 464 exceeds his grandson Peleg\'s 239 and all descendants through Terah). The longevity of the promise-line\'s most significant eponym may be deliberate emphasis.</p>',
    "17": '<p>Eber\'s additional 430 years: total 464. Eber is the last of the post-Babel patriarchs to live past 400 years. After Eber, the lifespans drop precipitously: Peleg (239), Reu (239), Serug (230), Nahor (148), Terah (205). This sudden drop in Peleg\'s generation corresponds to Peleg\'s name signifying the earth\'s division (10:25) — in the generation of the Babel dispersion, lifespans halve and the era of the patriarchs begins.</p>',
    "18": '<p>Peleg after 30 years fathers Reu. <strong>פֶּלֶג</strong> (<em>Peleḡ</em>) = "division" — his name marks the Babel generation. The genealogical line continues through Peleg (not Joktan) to reach Abram — the covenant line runs through the divided, dispersed world, not through the pre-division unity of Babel.</p>',
    "19": '<p>Peleg\'s remaining 209 years: total 239 years. The abrupt halving of the lifespan in Peleg\'s generation (from Eber\'s 464 to Peleg\'s 239) is the most dramatic transition in the post-Babel genealogy. Reu\'s lifespan (239 years, v. 21) matches Peleg\'s exactly — the two generations of Peleg and Reu mark the floor of the new lifespan era.</p>',
    "20": '<p>Reu after 32 years fathers Serug. The steady march of the genealogy moves the narrative toward Terah and Abram with increasing momentum — each generation brings the reader closer to the opening of the Abrahamic narrative in ch. 12. The genealogical bridge between the post-Babel world and the Patriarchal promises is being carefully constructed.</p>',
    "21": '<p>Reu\'s remaining 207 years: total 239 (matching Peleg\'s lifespan exactly). The genealogical precision continues without narrative commentary — the emphasis is on the unbroken chain of fatherhood from Shem to Abram, not on the individuals in the chain.</p>',
    "22": '<p>Serug after 30 years fathers Nahor. <strong>שְׂרוּג</strong> (<em>Sĕrûḡ</em>) — the name may be connected to the city Sarhugi/Serug in the Harran region (northwestern Mesopotamia), where Abraham\'s family will later settle (11:31-32). The geographical connection suggests the genealogy is also mapping the patriarchal family\'s homeland geography.</p>',
    "23": '<p>Serug\'s remaining 200 years: total 230. The progressive shortening continues: Serug (230) is shorter-lived than Reu (239) who is the same as Peleg (239). Nahor will live only 148 years (v. 25), the shortest lifespan in the post-Babel genealogy until Terah (205 = longer than Nahor but still in the new short-lifespan era).</p>',
    "24": '<p>Nahor after 29 years fathers Terah. <strong>נָחוֹר</strong> (<em>Nāḥôr</em>) — both the grandfather of Abram (here) and the brother of Abram (11:26-29) bear this name; the family naming pattern repeats names across generations, which is common in ANE genealogical practice. The Nahor of 11:22-25 is Abram\'s grandfather; Nahor in 11:26-29 is Abram\'s brother.</p>',
    "25": '<p>Nahor\'s remaining 119 years: total 148 — the shortest lifespan in the post-Babel genealogy. The dramatic decline from Shem\'s 600 to Nahor\'s 148 tracks across nine generations. The lifespan decline corresponds to the widening distance from the Flood (God\'s protective restraint of death) and the approaching era of the patriarchs, whose lifespans (Abraham 175, Isaac 180, Jacob 147, Joseph 110) are entirely within the human realm familiar to the ancient world.</p>',
    "26": '<p><strong>וַיְחִי-תֶרַח שִׁבְעִים שָׁנָה וַיּוֹלֶד אֶת-אַבְרָם אֶת-נָחוֹר וְאֶת-הָרָן</strong> — "Terah lived seventy years and fathered Abram, Nahor, and Haran." The narrative is on the verge of the Abrahamic promises. Note: Abram is listed first, though the chronology of 11:32 and 12:4 suggests he may not be the oldest son (if Terah was 70 when he fathered his first son, and Abram left Haran at 75 after Terah died at 205, Terah would have been 130 when Abram was born — meaning either Abram is the youngest of the three, or Abram is listed first by prominence rather than birth order, following the genealogical pattern of listing the significant son first).</p>',
    "27": '<p><strong>אֵלֶּה תּוֹלְדֹת תֶּרַח</strong> — "these are the generations/account of Terah." The final <em>tôlĕḏōt</em> formula before the Abrahamic narrative introduces Terah\'s family. The narrative now zooms from genealogical overview to dramatic close-up. <strong>הָרָן מֵת עַל-פְּנֵי תֶּרַח אָבִיו</strong> — "Haran died before/in the presence of (<em>ʿal-pĕnê</em>) his father Terah" — lit. "on the face of" = before the eyes of = while still alive. The premature death of Haran in Ur introduces the mortality theme that will haunt the Abrahamic narrative.</p>',
    "28": '<p><strong>בְּאֶרֶץ מוֹלַדְתּוֹ בְּאוּר כַּשְׂדִּים</strong> — "in his land of birth, in Ur of the Chaldeans." The specification of Ur as the family origin grounds the patriarchal narrative geographically. Ur was one of the great Sumerian city-states of Mesopotamia (modern Tell el-Muqayyar in southern Iraq), flourishing c. 2600-2000 BCE — a center of sophisticated urban civilization, astronomy, and the moon-god Nanna worship. The patriarchal family\'s origin in this cosmopolitan pagan city makes God\'s call to "leave your land" (12:1) a call out of the very center of the ancient world\'s civilized, urbanized order.</p>',
    "29": '<p><strong>וַיִּקַּח אַבְרָם וְנָחוֹר לָהֶם נָשִׁים</strong> — "Abram and Nahor took wives." <strong>שָׁרַי</strong> (<em>Śārāy</em>) — Sarai\'s name is the variant form of <em>śārāh</em> (princess/noblewoman, which God will rename her in 17:15); the exact relationship between the two forms is uncertain — possibly a dialect or archaic variant. <strong>מִלְכָּה</strong> (<em>Milkāh</em>) — "queen" (from <em>meleḵ</em>, king) — the sister of Lot, Haran\'s daughter. The immediate family circle is tight: Abram marries Sarai (his half-sister, 20:12); Nahor marries Milcah his niece.</p>',
    "30": '<p><strong>וַתְּהִי שָׂרַי עֲקָרָה אֵין לָהּ וָלָד</strong> — "now Sarai was barren; she had no child." <em>ʿĂqārāh</em> (barren) — from <em>ʿāqar</em> (to be barren, uprootedness). This single sentence creates the central tension of the entire Abrahamic narrative: the man God is about to promise "a great nation" (12:2) has a barren wife. The promise and the impossibility are placed in immediate juxtaposition — the covenant\'s fulfillment will require divine action beyond natural means. The matriarchal barrenness pattern (Sarai, Rebekah, Rachel; and Hannah, Manoah\'s wife in the later narrative) is introduced here as its inaugural instance.</p>',
    "31": '<p><strong>וַיֵּצְאוּ אִתָּם מֵאוּר כַּשְׂדִּים לָלֶכֶת אַרְצָה כְּנַעַן</strong> — "they went out with them from Ur of the Chaldeans to go to the land of Canaan." The journey to Canaan was Terah\'s initiative — he set out from Ur toward Canaan. But <strong>וַיָּבֹאוּ עַד-חָרָן וַיֵּשְׁבוּ שָׁם</strong> — "they came as far as Haran and settled there." The journey stopped at Haran (<em>Ḥārrān</em> in Akkadian, northwestern Mesopotamia, modern Harran in Turkey) — a city also associated with the moon-god worship and with the trade routes of the ANE. The incomplete journey creates the narrative gap that God\'s call of 12:1 will complete.</p>',
    "32": '<p><strong>וַיָּמָת תֶּרַח בְּחָרָן</strong> — "and Terah died in Haran." The death of Terah closes the transitional genealogy and creates the narrative space for Abram\'s call. Terah\'s 205 years (unexpectedly longer than his son Nahor\'s 148) makes him an outlier in the declining lifespan pattern — possibly reflecting the narrator\'s theological interest in having Abram leave during his father\'s lifetime, or a traditional variant in the patriarchal genealogy. Stephen\'s account in Acts 7:4 states that Abraham left Haran after his father died — aligning with the sequence: Terah dies (11:32), then God calls Abram (12:1).</p>'
  },
  "12": {
    "1": '<p><strong>וַיֹּאמֶר יְהוָה אֶל-אַבְרָם לֶךְ-לְךָ</strong> — "and the LORD said to Abram, \'go for yourself.\'" <em>Lēḵ-lĕḵā</em> — the doubled imperative with the reflexive/emphatic dative suffix (<em>-lĕḵā</em>, "for you/yourself") carries both a command to go and an implication that the going is for Abram\'s own ultimate benefit and fulfillment. The same construction appears at 22:2 (go to Moriah) — the two <em>lēḵ-lĕḵā</em> commands bracket the Abraham narrative as its opening and climactic test.</p><p>The three objects Abram must leave are expressed in three increasingly intimate concentric circles: <strong>מֵאַרְצְךָ</strong> (<em>mēʾarṣĕḵā</em>, from your land — largest, most general), <strong>וּמִמּוֹלַדְתְּךָ</strong> (<em>ûmimmôlaḏtĕḵā</em>, from your kindred/relatives), <strong>וּמִבֵּית אָבִיךָ</strong> (<em>ûmibbet ʾāḇîḵā</em>, from your father\'s household — smallest, most intimate). The movement is from general to particular — from geography to bloodline to immediate family. God demands the severance of all three layers of identity before naming the destination.</p>',
    "2": '<p><strong>וְאֶעֶשְׂךָ לְגוֹי גָּדוֹל</strong> (<em>wĕʾeʿeśĕḵā lĕḡôy gāḏôl</em>) — "and I will make you into a great nation." <em>Gôy</em> (nation, political entity) is the word used for all the nations in 10:5, 20, 31-32 — all the gôyim from the Table of Nations are here promised to be matched and exceeded by the one gôy that will come from Abram. Seven divine promises follow (counted differently by scholars, but conventionally seven): (1) I will make you a great nation; (2) I will bless you; (3) I will make your name great; (4) you will be a blessing; (5) I will bless those who bless you; (6) whoever curses you I will curse; (7) in you all the families of the earth will be blessed. The sevenfold structure mirrors the seven days of creation — a new creative act is beginning.</p><p><strong>וַאֲבָרֶכְךָ</strong> — "and I will bless you." <em>Bārak</em> (Piel, to bless) — the blessing formula that appeared in creation (1:22, 28), in Noah (9:1), and now in Abram. <strong>שְׁמְךָ גָּדוֹל</strong> — "your name great" — the reversal of Babel (11:4: "let us make a name for ourselves"). What humanity tried to achieve by city-building and tower-construction, God gives freely to the one who obeys the call to leave.</p>',
    "3": '<p><strong>וַאֲבָרְכָה מְבָרְכֶיךָ</strong> — "I will bless those who bless you." The reciprocal blessing/curse principle: those who bless Abram will be blessed; <strong>וּמְקַלֶּלְךָ אָאֹר</strong> — "whoever curses you I will curse" — the singular form (<em>mĕqallĕlĕḵā</em> is singular) for the cursing vs. the plural for blessing (<em>mĕbārĕḵeḵā</em>), possibly emphasizing that blessing is expected to be widespread but cursing rare.</p><p><strong>וְנִבְרְכוּ בְךָ כֹּל מִשְׁפְּחֹת הָאֲדָמָה</strong> — "and in you all the families of the earth will be blessed." <em>Wĕnibrĕḵû</em> — the key form: Niphal (passive) third-person plural imperfect. The Niphal reading (passive: they will be blessed) is supported by the MT vocalization and is the reading Paul uses in Gal 3:8 ("in you shall all the nations be blessed"). An alternative vocalization gives Hitpael (reflexive: they will bless themselves by you/call themselves blessed by you, as in Gen 18:18 and 22:18 where the form is different). The MT passive reading supports Paul\'s Christological application: the blessing flows through Abram to all nations, not merely that nations will invoke Abram\'s name in self-blessing.</p>',
    "4": '<p><strong>וַיֵּלֶךְ אַבְרָם כַּאֲשֶׁר דִּבֶּר אֵלָיו יְהוָה</strong> — "so Abram went, as the LORD had spoken to him." The obedience formula — as with Noah (6:22; 7:5; 7:9) — signals total and immediate compliance. Hebrews 11:8 comments: "By faith Abraham obeyed when he was called to go out to a place that he was to receive as an inheritance. And he went out, not knowing where he was going" — the narrative does not tell Abram his destination before he leaves, only that God will show him the land (12:1: "the land I will show you"). The going precedes the knowing.</p>',
    "5": '<p><strong>אֶת-כָּל-רְכוּשָׁם אֲשֶׁר רָכָשׁוּ וְאֶת-הַנֶּפֶשׁ אֲשֶׁר-עָשׂוּ בְחָרָן</strong> — "all the possessions they had accumulated and the people (<em>nepeš</em>) they had acquired in Haran." <em>Nepeš</em> here in the sense of persons/slaves — "the souls they had made/acquired." <em>ʿĀśû</em> (they made/acquired) applied to persons: either the slaves and servants accumulated as wealth (standard ANE household servants), or possibly (rabbinic reading) converts/proselytes made in Haran. The word <em>nepeš</em> keeps the human-dignity dimension: these are living persons, not mere property, even if legally held as servants.</p>',
    "6": '<p><strong>אֵלוֹן מוֹרֶה</strong> (<em>ʾēlôn môreh</em>) — "the oak/terebinth of Moreh." <em>Môreh</em> = teacher, oracle-giver (from <em>yārāh</em>, to teach, to direct). The oak of Moreh at Shechem (<em>Šĕḵem</em>) was likely a divination site — a sacred tree associated with the receiving of oracles or instruction. Abram\'s first stop in Canaan is at a pagan sacred site, where YHWH appears to him (v. 7). God meets Abram at the very location where the Canaanites sought their gods — the LORD\'s theophany at a Canaanite holy site is itself a territorial claim.</p><p><strong>וְהַכְּנַעֲנִי אָז בָּאָרֶץ</strong> — "and the Canaanite was then in the land." The parenthetical note acknowledges the obvious difficulty: the land God is promising to Abram\'s descendants is occupied. The note is not an explanation but an observation — the promise is made in full knowledge of the existing inhabitants.</p>',
    "7": '<p><strong>וַיֵּרָא יְהוָה אֶל-אַבְרָם</strong> (<em>wayyērāʾ YHWH ʾel-ʾabrām</em>) — "and the LORD appeared to Abram." <em>Nîrāʾ</em> (Niphal perfect, lit. "was seen" or "appeared") — the theophany verb used for all patriarchal appearances of God (17:1; 18:1; 26:2, 24; 35:1, 9; 46:29; 48:3). The form indicates that God made himself visible to Abram — the nature of the appearance is not described, but it is an objective visible event, not merely an inner impression. <strong>לְזַרְעֲךָ אֶתֵּן אֶת-הָאָרֶץ הַזֹּאת</strong> — "to your offspring (<em>zeraʿ</em>) I will give this land." The land-promise is to the <em>zeraʿ</em> (seed/offspring) — the same collective-or-singular word that carried the promise in 3:15. The land promise is to Abram\'s descendants, not yet to Abram personally.</p>',
    "8": '<p><strong>וַיִּבֶן שָׁם מִזְבֵּחַ לַיהוָה</strong> — "and he built there an altar to the LORD." Altar-building punctuates Abram\'s journey through the land: 12:7 (at Shechem, after the first theophany), 12:8 (at Bethel), 13:18 (at Mamre/Hebron), 22:9 (at Moriah). Each altar marks a site of divine encounter and Abrahamic worship — Abram is marking the land with worship of YHWH, establishing a counter-presence to the Canaanite cult sites. <strong>וַיִּקְרָא בְּשֵׁם יְהוָה</strong> — "and he called on the name of the LORD" — the worship formula introduced at 4:26 (Enosh\'s generation began calling on the LORD\'s name). Abram continues this line of YHWH-worshippers in Canaan.</p>',
    "9": '<p><strong>וַיִּסַּע אַבְרָם הָלוֹךְ וְנָסוֹעַ הַנֶּגְבָּה</strong> — "Abram journeyed on, going and setting out toward the Negev." The infinitive absolute construction <em>hālôḵ wĕnāsôaʿ</em> (going and journeying = journeying progressively, continually moving) describes a steady southward migration. The Negev (<em>hanneḡeḇ</em>, the dry south) is the semi-arid region between Judah and the Sinai — Abram is moving from central Canaan toward the southern borderlands before the Egyptian episode.</p>',
    "10": '<p><strong>וַיְהִי רָעָב בָּאָרֶץ</strong> — "now there was a famine in the land." The famine (<em>rāʿāb</em>) is the narrative pressure that drives Abram into Egypt — the land of promise cannot yet sustain its future heir. The same pressure (famine → Egypt) will drive Jacob\'s family to Egypt in 42:5; 43:1 — the Abram/Egypt episode is a structural anticipation of the Exodus narrative. <strong>לָגוּר שָׁם</strong> — "to sojourn (<em>gûr</em>) there" — <em>gûr</em> is the word for resident-alien sojourning, the status of someone living outside their native land without full citizen rights (cf. 17:8; 20:1; 21:23, 34; 26:3 — Abram consistently sojourns rather than owning the land).</p>',
    "11": '<p><strong>הִנֵּה-נָא יָדַעְתִּי כִּי אִשָּׁה יְפַת-מַרְאֶה אָתְּ</strong> — "behold, I know that you are a beautiful woman in appearance." <em>Yĕpat-marʾeh</em> (beautiful of appearance/sight) — the standard biblical beauty idiom; cf. 26:7 (Rebekah) and 29:17 (Rachel). Abram\'s speech to Sarai reveals his fear before the fact: he plans the deception before it is necessary. <em>Yāḏaʿtî</em> (I know) — the knowing is intimate and certain; Abram is under no illusion about the danger his wife\'s beauty creates.</p>',
    "12": '<p><strong>וְהָרְגוּ אֹתִי וְאֹתָךְ יְחַיּוּ</strong> — "they will kill me and let you live." The calculus is stark: Abram\'s life vs. Sarai\'s freedom. The wife-sister ruse (repeated in 20:1-18 with Abimelech and in 26:6-11 with Isaac and Rebekah) is Abram\'s default survival strategy — one that places Sarai in danger to preserve himself. The text presents this without direct authorial condemnation, but the narrative consequence (Pharaoh\'s righteous indignation in vv. 18-19; the divine plagues in v. 17) functions as implicit moral assessment.</p>',
    "13": '<p><strong>אִמְרִי-נָא אֲחֹתִי אָתְּ</strong> — "say, please, that you are my sister." The request uses the particle <em>nāʾ</em> (please, I beg you) — indicating deference/request rather than command. In 20:12, Abram acknowledges that Sarai is indeed his half-sister (daughter of the same father, different mother), so the statement is technically true while functionally deceptive. The use of a partial truth to create a false impression raises the question of whether Abram\'s action is acceptable self-protection or cowardly deception — the narrative\'s non-resolution of this question is itself a literary feature.</p>',
    "14": '<p><strong>כִּי-יָפָה הִוא מְאֹד</strong> — "for she was very beautiful." <em>Mĕʾōḏ</em> (very, greatly) — the same intensifier as the creation\'s "very good" (1:31). Sarai\'s beauty is extreme enough to be noticed by Egyptians immediately. The Egyptians\' observation (<em>wayirĕʾû</em>) leading to official commendation (v. 15) follows quickly — the plan Abram feared comes true within verses of his warning to Sarai.</p>',
    "15": '<p><strong>וַיְהַלְלוּ אֹתָהּ אֶל-פַּרְעֹה</strong> (<em>wayĕhallĕlû ʾōtāh ʾel-parʿōh</em>) — "and they praised her to Pharaoh." <em>Hālal</em> (Piel, to praise, commend, boast of) — the root of <em>hallĕlûyāh</em> (praise YHWH). Officials who see Sarai perform the same verb as worship: they extol her beauty to the king. <em>Parʿōh</em> (Pharaoh) — the Hebrew rendering of the Egyptian royal title <em>pr-ʿȝ</em> (great house), used for all Egyptian kings in the OT regardless of dynasty. Sarai is taken into the royal harem — the word <em>bêt parʿōh</em> (Pharaoh\'s house) is a term for the royal household/palace.</p>',
    "16": '<p><strong>וּלְאַבְרָם הֵיטִיב בַּעֲבוּרָהּ</strong> — "and he dealt well with Abram for her sake." The material benefit Abram sought (v. 13: "that it may go well with me for your sake") is realized: sheep, cattle, donkeys, servants (<em>ʿăbāḏîm wəšipḥōt</em>), female donkeys, and camels. The material enrichment of Abram from the Egyptian sojourn (continued in 13:2: "Abram was very rich") parallels and anticipates the Exodus: Israel will be enriched by the Egyptians as they leave (Exod 12:35-36). The Egypt-sojourn typology runs deep.</p>',
    "17": '<p><strong>וַיְנַגַּע יְהוָה אֶת-פַּרְעֹה נְגָעִים גְּדֹלִים</strong> — "and the LORD afflicted Pharaoh with great plagues." <em>Nāgaʿ</em> (Piel, to strike, afflict) + <em>nĕgāʿîm</em> (plagues, afflictions) — the same root for the Exodus plagues (<em>nāgaʿ</em> in Exod 11:1; the noun <em>nega</em> appears throughout Leviticus for skin diseases/impurities). The word-pair <em>nāgaʿ/nĕgāʿîm</em> creates an explicit etymological link between this mini-Exodus and the actual Exodus — Pharaoh afflicts Israel, God afflicts Pharaoh, in both the proto-Exodus (ch. 12) and the Exodus proper. The divine protection of Sarai (and thus the promise-line) is enacted without Abram\'s initiative or moral worthiness.</p>',
    "18": '<p><strong>מַה-זֹּאת עָשִׂיתָ לִּי</strong> — "what is this you have done to me?" Pharaoh\'s rhetorical question exactly mirrors God\'s question to the woman after the Fall (3:13: "what is this you have done?") and to Cain after the murder (4:10: "what have you done?"). The pagan ruler\'s moral indignation uses the same formula as divine judicial inquiry — the irony is rich: the one who should be the least morally sophisticated is asking the question most associated with divine judgment. Pharaoh\'s rhetorical position is ethically superior to Abram\'s in this moment.</p>',
    "19": '<p><strong>לָמָּה אָמַרְתָּ אֲחֹתִי הִוא</strong> — "why did you say \'she is my sister\'?" The threefold rhetorical accusation (<em>mah-zōʾt ʿāśîtā lî</em>, v. 18; <em>lāmmāh ʾāmartā</em>, v. 19a; <em>lāmmāh lōʾ higgaḏtā lî</em>, v. 18) builds through repetition. Pharaoh\'s "now then, here is your wife" (<em>wĕʿattāh hinnēh ʾištĕḵā</em>) restores Sarai with a formal directive — the pagan king acts with more honor than the patriarch. The narrative does not record Abram\'s response to this indictment — his silence is as theologically significant as Pharaoh\'s words.</p>',
    "20": '<p><strong>וַיְצַו עָלָיו פַּרְעֹה אֲנָשִׁים</strong> — "Pharaoh gave orders about him to his men." The expulsion of Abram from Egypt with his wife and possessions intact parallels and anticipates the Exodus: Israel leaves Egypt with Egyptian goods (Exod 12:35-36), escorted out by Pharaoh\'s command. The proto-Exodus that began with Abram\'s descent to Egypt in famine (12:10), the affliction of Pharaoh\'s household (12:17), and the departure with wealth (12:20; 13:2) provides the narrative template for the full Exodus of Israel\'s descendants centuries later. Abram is Israel in miniature.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'genesis')
    merge_comm(existing, GENESIS)
    save_comm('mkt-original', 'genesis', existing)
    print('Genesis 10-12 mkt-original written.')

if __name__ == '__main__':
    main()
